export const STORAGE_KEY = "fastapi_base_url";
const API_VERSION = "v1";

// Default API URLs to try (in order)
const DEFAULT_API_URLS = [
  "http://localhost:8000",
  "https://aiinvest-backend.fly.dev",
  "https://aiinvest-api.onrender.com",
];

// Cache for validated URL
let cachedValidUrl: string | null = null;

export function getApiBaseUrl(): string {
  // Return cached valid URL if available
  if (cachedValidUrl) return cachedValidUrl;

  // Check localStorage first
  const stored = localStorage.getItem(STORAGE_KEY);
  if (stored) {
    cachedValidUrl = stored;
    return stored;
  }

  // Return first default URL
  const defaultUrl = DEFAULT_API_URLS[0];
  localStorage.setItem(STORAGE_KEY, defaultUrl);
  cachedValidUrl = defaultUrl;
  return defaultUrl;
}

export function setApiBaseUrl(url: string) {
  const cleanUrl = url.replace(/\/+$/, "");
  localStorage.setItem(STORAGE_KEY, cleanUrl);
  cachedValidUrl = cleanUrl;
}

export function clearApiBaseUrl() {
  localStorage.removeItem(STORAGE_KEY);
  cachedValidUrl = null;
}

export function getApiVersion(): string {
  return API_VERSION;
}

export function getDefaultApiUrls(): string[] {
  return [...DEFAULT_API_URLS];
}

// Check if API is reachable
export async function checkApiHealth(baseUrl?: string): Promise<boolean> {
  const url = baseUrl || getApiBaseUrl();
  const timeoutSignal =
    typeof AbortSignal !== "undefined" && typeof AbortSignal.timeout === "function"
      ? AbortSignal.timeout(5000)
      : undefined;
  try {
    const res = await fetch(`${url}/health`, {
      ...(timeoutSignal ? { signal: timeoutSignal } : {}),
      headers: { "ngrok-skip-browser-warning": "true" }
    });
    return res.ok;
  } catch {
    return false;
  }
}

// Auto-detect working API URL
export async function autoDetectApiUrl(): Promise<string | null> {
  // Check stored URL first
  const stored = localStorage.getItem(STORAGE_KEY);
  if (stored && await checkApiHealth(stored)) {
    cachedValidUrl = stored;
    return stored;
  }

  // Try default URLs
  for (const url of DEFAULT_API_URLS) {
    if (await checkApiHealth(url)) {
      localStorage.setItem(STORAGE_KEY, url);
      cachedValidUrl = url;
      return url;
    }
  }

  return null;
}

export async function apiFetch(
  path: string,
  options?: RequestInit & { params?: Record<string, string> }
) {
  const base = getApiBaseUrl();
  if (!base) throw new Error("未配置后端 API 地址");

  const url = new URL(`/api/${API_VERSION}${path}`, base);
  if (options?.params) {
    Object.entries(options.params).forEach(([k, v]) => url.searchParams.set(k, v));
  }

  const { data: { session } } = await supabase.auth.getSession();
  const isFormData = options?.body instanceof FormData;
  const headers: Record<string, string> = {
    ...(isFormData ? {} : { "Content-Type": "application/json" }),
    "Accept": `application/vnd.app.${API_VERSION}+json`,
    "ngrok-skip-browser-warning": "true",
    ...(options?.headers as Record<string, string>),
  };
  if (session?.access_token) {
    headers["Authorization"] = `Bearer ${session.access_token}`;
  }

  const res = await fetch(url.toString(), { ...options, headers });
  return res;
}
