import { describe, it, expect, vi, beforeEach, type Mock } from "vitest";
import "./setup-bun";

vi.mock("@/integrations/supabase/client", () => ({
  supabase: {
    auth: {
      getSession: vi.fn(() => Promise.resolve({ data: { session: null }, error: null })),
    },
  },
}));

import * as apiModule from "@/lib/api";
import { knowledgeService } from "@/services/knowledge.service";
import { marketService } from "@/services/market.service";
import { portfolioService } from "@/services/portfolio.service";
import { langGraphVizService } from "@/services/langgraph-viz.service";

const jsonResponse = (body: unknown, ok = true) =>
  ({
    ok,
    status: ok ? 200 : 500,
    statusText: ok ? "OK" : "Error",
    json: async () => body,
  }) as Response;

function mockApiFetch(): void {
  const fn = vi.spyOn(apiModule, "apiFetch") as Mock;
  fn.mockImplementation(async (path: string) => {
    if (path.startsWith("/knowledge/add")) {
      return jsonResponse({ entry_id: 42, success: true });
    }
    if (path.startsWith("/knowledge/stats")) {
      return jsonResponse({ total_entries: 0 });
    }
    if (path.includes("/market/quotes/")) {
      return jsonResponse({
        symbol: "AAPL",
        timestamp: new Date().toISOString(),
        price: {
          current: 1,
          open: 1,
          high: 1,
          low: 1,
          previous_close: 1,
          volume: 1,
        },
        change: { absolute: 0, percent: 0 },
        market: { market_cap: 1, exchange: "NASDAQ", currency: "USD" },
        market_status: "open",
      });
    }
    if (path.includes("/market/history/")) {
      return jsonResponse({
        symbol: "AAPL",
        period: "1mo",
        data: [],
        start_date: "2020-01-01",
        end_date: "2020-02-01",
      });
    }
    if (path.startsWith("/market/search")) {
      return jsonResponse([]);
    }
    if (path.startsWith("/market/status")) {
      return jsonResponse({
        status: "open",
        market: "us",
        current_time: new Date().toISOString(),
      });
    }
    if (path.startsWith("/portfolio/create")) {
      return jsonResponse({
        portfolio_id: "pf-test-1",
        name: "Test",
        cash: 10000,
        initial_cash: 10000,
        total_value: 10000,
        total_pnl: 0,
        positions: [],
        trades: [],
        created_at: new Date().toISOString(),
      });
    }
    if (path.includes("/close-position/")) {
      return jsonResponse({ success: true, order_id: "o1", message: "ok" });
    }
    if (path.includes("/close-all")) {
      return jsonResponse({ success: true, positions_closed: 0, message: "ok" });
    }
    if (path.startsWith("/langgraph/mermaid")) {
      return jsonResponse({
        diagram: "graph TD",
        format: "mermaid",
        workflow: "default",
      });
    }
    if (path.startsWith("/langgraph/structure")) {
      return jsonResponse({
        nodes: [],
        edges: [],
        entry_point: "start",
        exit_points: ["end"],
      });
    }
    if (path.startsWith("/langgraph/llm-config")) {
      return jsonResponse({
        workflow: "default",
        llm_nodes: [],
        config: {
          provider: "openai",
          model: "gpt-4",
          temperature: 0.2,
          max_tokens: 4096,
        },
        description: {},
      });
    }
    return jsonResponse({ error: "unmocked path", path }, false);
  });
}

describe("API Coverage Tests", () => {
  beforeEach(() => {
    vi.restoreAllMocks();
    mockApiFetch();
  });

  it("Knowledge: add entry", async () => {
    const result = await knowledgeService.add({
      knowledge_type: "technical",
      symbol: "AAPL",
      title: "Test Entry",
      content: "Test content",
      confidence: "low",
      tags: ["test"],
    });
    expect(result).toHaveProperty("entry_id");
  });

  it("Knowledge: get stats", async () => {
    const stats = await knowledgeService.getStats();
    expect(stats).toBeDefined();
  });

  it("Market: get quote", async () => {
    const quote = await marketService.getQuote("AAPL");
    expect(quote).toHaveProperty("symbol", "AAPL");
  });

  it("Market: get history", async () => {
    const history = await marketService.getHistory("AAPL");
    expect(history).toHaveProperty("symbol", "AAPL");
  });

  it("Market: search", async () => {
    const results = await marketService.search("AAPL");
    expect(Array.isArray(results)).toBe(true);
  });

  it("Market: get status", async () => {
    const status = await marketService.getStatus("us");
    expect(status).toHaveProperty("status");
  });

  it("Portfolio: create and close-position", async () => {
    const created = await portfolioService.create({ name: "Test", initial_cash: 10000 });
    expect(created).toHaveProperty("portfolio_id");

    try {
      await portfolioService.closePosition(created.portfolio_id, "AAPL");
    } catch {
      // Unexpected with mock
    }
  });

  it("Portfolio: close-all", async () => {
    const created = await portfolioService.create({ name: "Test2", initial_cash: 10000 });
    try {
      await portfolioService.closeAll(created.portfolio_id);
    } catch {
      // Unexpected with mock
    }
  });

  it("LangGraph Viz: get mermaid", async () => {
    const diagram = await langGraphVizService.getMermaid();
    expect(diagram).toHaveProperty("diagram");
  });

  it("LangGraph Viz: get structure", async () => {
    const structure = await langGraphVizService.getStructure();
    expect(structure).toHaveProperty("nodes");
    expect(structure).toHaveProperty("edges");
  });

  it("LangGraph Viz: get llm-config", async () => {
    const config = await langGraphVizService.getLLMConfig();
    expect(config).toHaveProperty("config");
  });
});

// Browser console helper (live backend)
if (typeof window !== "undefined") {
  (window as unknown as { testApiCoverage?: () => Promise<void> }).testApiCoverage = async () => {
    console.log("Testing API coverage (live)...");
