      await knowledgeService.add({ knowledge_type: "technical", title: "Test", content: "Test" });
      await knowledgeService.getStats();
      await marketService.getQuote("AAPL");
      await marketService.getHistory("AAPL");
      await marketService.search("AAPL");
      await marketService.getStatus("us");
      const pf = await portfolioService.create({ name: "Test", initial_cash: 10000 });
      try {
        await portfolioService.closePosition(pf.portfolio_id, "AAPL");
