      await langGraphVizService.getMermaid();
      await langGraphVizService.getStructure();
      await langGraphVizService.getLLMConfig();
      console.log("✅ All live API coverage checks finished.");
    } catch (e) {
      console.error("❌ API test failed:", e);
    }
  };
}
